from __future__ import annotations

from datetime import datetime, timedelta, timezone
from io import BytesIO
from typing import Any
from zipfile import ZIP_DEFLATED, ZipFile

from jose import jwt

from app.core.config import settings

ONLYOFFICE_ALGORITHM = "HS256"


def build_onlyoffice_secret() -> str:
    return settings.onlyoffice_jwt_secret or settings.auth_jwt_secret_key


def build_access_token(employee_id: str, draft_id: str, purpose: str) -> str:
    expires_at = datetime.now(timezone.utc) + timedelta(minutes=settings.onlyoffice_token_ttl_minutes)
    payload = {
        "employee_id": employee_id,
        "draft_id": draft_id,
        "purpose": purpose,
        "exp": int(expires_at.timestamp()),
    }
    return jwt.encode(payload, build_onlyoffice_secret(), algorithm=ONLYOFFICE_ALGORITHM)


def verify_access_token(token: str, employee_id: str, draft_id: str, purpose: str) -> None:
    payload = jwt.decode(token, build_onlyoffice_secret(), algorithms=[ONLYOFFICE_ALGORITHM])
    if payload.get("employee_id") != employee_id or payload.get("draft_id") != draft_id or payload.get("purpose") != purpose:
        raise ValueError("Invalid draft access token")


def sign_onlyoffice_config(config: dict[str, Any]) -> dict[str, Any]:
    signed = dict(config)
    signed["token"] = jwt.encode(config, build_onlyoffice_secret(), algorithm=ONLYOFFICE_ALGORITHM)
    return signed


def build_blank_docx_bytes(title: str) -> bytes:
    import base64
    valid_docx_b64 = ""
    return base64.b64decode(valid_docx_b64)
